import jQuery from "jquery";
import "jquery-ui/ui/widget.js";
(function ($) {
  "use strict";

  $.widget("ra.abstractSelect", {
    options: {
      createQuery: function createQuery(query) {
        if ($.isEmptyObject(this.scopeBy)) {
          return {
            query: query
          };
        } else {
          var filterQuery = {};
          for (var field in this.scopeBy) {
            var targetField = this.scopeBy[field];
            var targetValue = $("[name$=\"[".concat(field, "]\"]")).val();
            if (!filterQuery[targetField]) {
              filterQuery[targetField] = [];
            }
            filterQuery[targetField].push(targetValue ? {
              o: "is",
              v: targetValue
            } : {
              o: "_blank"
            });
          }
          return {
            query: query,
            f: filterQuery
          };
        }
      },
      scopeBy: {}
    }
  });
})(jQuery);